using SchoolEnterprise.Models.Domain; using SchoolEnterprise.Services; namespace SchoolEnterprise.Repositories; public class TeacherRepository(XmlStorageService storage) : BaseXmlRepository<Teacher>(storage){ protected override string FileName=>"teachers.xml"; public Teacher? GetById(int id)=>GetAll().FirstOrDefault(x=>x.TeacherId==id); public void Add(Teacher i){var a=GetAll();a.Add(i);SaveAll(a);} public void Update(Teacher i){var a=GetAll();var x=a.FindIndex(t=>t.TeacherId==i.TeacherId);if(x>=0){a[x]=i;SaveAll(a);}} public void Delete(int id){var a=GetAll();a.RemoveAll(x=>x.TeacherId==id);SaveAll(a);} }
